/**
 * @name ShortcutConfigurable getValue processes route filter/predicate args as SpEL
 * @description The entryValue parameter in ShortcutConfigurable.getValue is passed to SpEL parseExpression without sanitization
 * @kind path-problem
 * @problem.severity error
 * @id java/shortcut-configurable-spel-path
 * @tags security
 *       external/cwe/cwe-917
 */

import java
import semmle.code.java.dataflow.TaintTracking

module ShortcutSpELConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // The entryValue parameter of ShortcutConfigurable.getValue
    exists(Method m, Parameter p |
      m.getDeclaringType().hasQualifiedName("org.springframework.cloud.gateway.support", "ShortcutConfigurable") and
      m.hasName("getValue") and
      p = m.getAParameter() and
      p.getName() = "entryValue" |
      source.asParameter() = p
    )
  }

  predicate isSink(DataFlow::Node sink) {
    exists(MethodCall mc |
      mc.getMethod().hasName("parseExpression") and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName(
        "org.springframework.expression", "ExpressionParser") |
      sink.asExpr() = mc.getArgument(0)
    )
  }
}

module ShortcutSpELFlow = TaintTracking::Global<ShortcutSpELConfig>;
import ShortcutSpELFlow::PathGraph

from ShortcutSpELFlow::PathNode source, ShortcutSpELFlow::PathNode sink
where ShortcutSpELFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "ShortcutConfigurable entryValue flows to SpEL parseExpression from $@.", source.getNode(), "entryValue parameter"

/**
 * @name ConfigurationService bind - taint from route definition args to SpEL
 * @description ConfigurationService.bind() receives route filter/predicate args map and passes values to ShortcutConfigurable for SpEL evaluation
 * @kind path-problem
 * @problem.severity error
 * @id java/config-service-bind-to-spel
 * @tags security
 *       external/cwe/cwe-917
 *       external/cwe/cwe-094
 */

import java
import semmle.code.java.dataflow.TaintTracking

module ConfigServiceSpELConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // Parameters of ConfigurationService methods that take args maps
    exists(Method m |
      m.getDeclaringType().hasQualifiedName(
        "org.springframework.cloud.gateway.support", "ConfigurationService") and
      (m.hasName("bind") or m.hasName("with")) |
      source.asParameter() = m.getAParameter()
    )
    or
    // getArgs() calls - the map of filter/predicate arguments from route definitions
    exists(MethodCall mc |
      mc.getMethod().hasName("getArgs") |
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    exists(MethodCall mc |
      mc.getMethod().hasName("parseExpression") and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName(
        "org.springframework.expression", "ExpressionParser") |
      sink.asExpr() = mc.getArgument(0)
    )
  }

  predicate isAdditionalFlowStep(DataFlow::Node n1, DataFlow::Node n2) {
    exists(MethodCall mc |
      mc.getMethod().hasName("values") or
      mc.getMethod().hasName("get") or
      mc.getMethod().hasName("entrySet") or
      mc.getMethod().hasName("getValue") |
      n1.asExpr() = mc.getQualifier() and n2.asExpr() = mc
    )
  }
}

module ConfigServiceSpELFlow = TaintTracking::Global<ConfigServiceSpELConfig>;
import ConfigServiceSpELFlow::PathGraph

from ConfigServiceSpELFlow::PathNode source, ConfigServiceSpELFlow::PathNode sink
where ConfigServiceSpELFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Route definition args flow to SpEL from $@.", source.getNode(), "route args source"

/**
 * @name Route definition args string values flowing to SpEL evaluation - getArgs chain
 * @description getArgs() map values from FilterDefinition/PredicateDefinition flowing into ShortcutConfigurable.getValue -> SpEL
 * @kind path-problem
 * @problem.severity error
 * @id java/route-args-to-spel
 * @tags security
 *       external/cwe/cwe-917
 *       external/cwe/cwe-094
 */

import java
import semmle.code.java.dataflow.TaintTracking

module RouteArgsSpELConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // getArgs() returns the Map<String,String> of filter/predicate arguments
    exists(MethodCall mc |
      mc.getMethod().hasName("getArgs") and
      (
        mc.getMethod().getDeclaringType().hasQualifiedName(
          "org.springframework.cloud.gateway.filter", "FilterDefinition") or
        mc.getMethod().getDeclaringType().hasQualifiedName(
          "org.springframework.cloud.gateway.handler.predicate", "PredicateDefinition")
      ) |
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    exists(MethodCall mc |
      mc.getMethod().hasName("parseExpression") and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName(
        "org.springframework.expression", "ExpressionParser") |
      sink.asExpr() = mc.getArgument(0)
    )
  }

  predicate isAdditionalFlowStep(DataFlow::Node n1, DataFlow::Node n2) {
    exists(MethodCall mc |
      mc.getMethod().hasName("values") or mc.getMethod().hasName("get") or
      mc.getMethod().hasName("entrySet") or mc.getMethod().hasName("getValue") or
      mc.getMethod().hasName("iterator") or mc.getMethod().hasName("next") |
      n1.asExpr() = mc.getQualifier() and n2.asExpr() = mc
    )
  }
}

module RouteArgsSpELFlow = TaintTracking::Global<RouteArgsSpELConfig>;
import RouteArgsSpELFlow::PathGraph

from RouteArgsSpELFlow::PathNode source, RouteArgsSpELFlow::PathNode sink
where RouteArgsSpELFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Filter/Predicate args map flows to SpEL parseExpression from $@.", source.getNode(), "getArgs() call"

/**
 * @name Expression language injection check - getValue calls with user-controlled expressions
 * @description SpEL getValue calls that may process user-controlled expression strings
 * @kind path-problem
 * @problem.severity error
 * @id java/spel-getvalue-injection
 * @tags security
 *       external/cwe/cwe-917
 */

import java
import semmle.code.java.dataflow.TaintTracking

module SpELGetValueConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // entryValue parameter in ShortcutConfigurable.getValue
    exists(Method m, Parameter p |
      m.getDeclaringType().hasQualifiedName(
        "org.springframework.cloud.gateway.support", "ShortcutConfigurable") and
      m.hasName("getValue") and
      p.getName() = "entryValue" |
      source.asParameter() = p
    )
    or
    // getArgs() from filter/predicate definitions flowing into normalize/apply
    exists(MethodCall mc |
      mc.getMethod().hasName("getArgs") |
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // Expression.getValue() - the actual evaluation after parsing
    exists(MethodCall mc |
      mc.getMethod().hasName("getValue") and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName(
        "org.springframework.expression", "Expression") |
      sink.asExpr() = mc.getQualifier()
    )
  }

  predicate isAdditionalFlowStep(DataFlow::Node n1, DataFlow::Node n2) {
    // parseExpression returns an Expression that is then evaluated via getValue
    exists(MethodCall mc |
      mc.getMethod().hasName("parseExpression") |
      n1.asExpr() = mc.getArgument(0) and n2.asExpr() = mc
    )
  }
}

module SpELGetValueFlow = TaintTracking::Global<SpELGetValueConfig>;
import SpELGetValueFlow::PathGraph

from SpELGetValueFlow::PathNode source, SpELGetValueFlow::PathNode sink
where SpELGetValueFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "User-controlled value flows to SpEL getValue() evaluation from $@.", source.getNode(), "user-controlled input"
